/*
Bulk-build nested JSON in one pass.
- No SplitInBatches.
- Aggressively maps fields (keeps raw property_* too).

Desired nesting rules:
- Project:
  - collections[] (each collection includes its own items/resources/assets/thumbnail)
  - resources[]
  - assets[]
  - workLogs[]   <-- added
  - thumbnail (single related asset or null)
- Collection:
  - items[] (assets referenced by property_collection_items)
  - resources[]
  - assets[] (assets that reference the collection via their own relation)
  - thumbnail (single related asset or null)
- Asset:
  - resources[]
  - thumbnail (single related asset or null)

Expected Notion shapes from your workflow:
- Projects (showcase): property_* fields like property_name, property_summary, property_collections, property_assets, property_resources, etc.
- Collections: property_projects, property_thumbnail (optional), property_collection_items (relation to assets), etc.
- Assets: property_projects, property_collections, property_thumbnail (relation to another asset), etc.
- Resources: property_projects, property_collections, property_assets
- Work Log: property_project (relation to project), property_date, property_entry, etc.
*/

const uniq = (arr) => Array.from(new Set((arr ?? []).filter(Boolean)));

function safeArray(v) {
  return Array.isArray(v) ? v : (v == null ? [] : [v]);
}

function pickFirst(v) {
  const a = safeArray(v);
  return a.length ? a[0] : null;
}

function dedupById(arr) {
  const seen = new Set();
  const out = [];
  for (const x of arr ?? []) {
    const id = x?.id ?? JSON.stringify(x);
    if (!seen.has(id)) {
      seen.add(id);
      out.push(x);
    }
  }
  return out;
}

function parseDateValue(v) {
  if (!v) return null;
  if (typeof v === "string") return v;
  if (typeof v === "object" && v.start) return v.start;
  return null;
}

function parseStartedLastUpdateRange(v) {
  const value = pickFirst(v) ?? v;
  if (!value) {
    return {
      raw: null,
      startedAt: null,
      lastUpdateAt: null,
    };
  }

  if (typeof value === "string") {
    return {
      raw: value,
      startedAt: value,
      lastUpdateAt: null,
    };
  }

  if (typeof value === "object") {
    return {
      raw: value,
      startedAt: parseDateValue(value.start ?? value),
      lastUpdateAt: parseDateValue(value.end),
    };
  }

  return {
    raw: null,
    startedAt: null,
    lastUpdateAt: null,
  };
}

function sortByDateDesc(arr, getDate) {
  return [...(arr ?? [])].sort((a, b) => {
    const da = getDate(a);
    const db = getDate(b);
    const ta = da ? Date.parse(da) : 0;
    const tb = db ? Date.parse(db) : 0;
    return tb - ta;
  });
}

const PROJECT_SINGLE_ASSET_RELATION_EXCLUDE = new Set([
  "property_assets",
  "property_collections",
  "property_resources",
  "property_title",
]);

const PROJECT_MEDIA_HINT_RE =
  /(thumbnail|banner|icon|poster|hero|image|cover|logo|artwork|media|preview|screenshot)/i;

function stripPropertyPrefix(key) {
  return String(key ?? "").replace(/^property_/, "");
}

function getFirstRelationId(v) {
  const first = pickFirst(v);
  if (!first) return null;
  if (typeof first === "string") return first;
  if (typeof first === "object") return first.id ?? null;
  return null;
}

function resolveSingleAssetRelation(row, propertyKey, assetById) {
  const relationId = getFirstRelationId(row?.[propertyKey]);
  if (!relationId) return { relationId: null, asset: null };
  const rawAsset = assetById[relationId];
  return {
    relationId,
    asset: rawAsset ? normalizeThumbnail(rawAsset) : null,
  };
}

function detectProjectSingleAssetRelationKeys(projectRows, assetById) {
  const keys = new Set(["property_thumbnail"]);

  for (const row of projectRows ?? []) {
    for (const [key, value] of Object.entries(row ?? {})) {
      if (!key.startsWith("property_")) continue;
      if (PROJECT_SINGLE_ASSET_RELATION_EXCLUDE.has(key)) continue;

      const values = safeArray(value);
      if (values.length > 1) continue;

      if (values.length === 0) {
        if (PROJECT_MEDIA_HINT_RE.test(key)) keys.add(key);
        continue;
      }

      const relationId = getFirstRelationId(values);
      if (relationId && assetById[relationId]) {
        keys.add(key);
        continue;
      }

      if (PROJECT_MEDIA_HINT_RE.test(key)) keys.add(key);
    }
  }

  return [...keys];
}

function normalizeResource(r) {
  return {
    id: r.id ?? null,
    name: r.name ?? null,
    label: r.property_label ?? null,
    type: r.property_type ?? null,
    url: r.property_url ?? null,
    icon: r.property_icon ?? null,

    projectIds: uniq(r.property_projects),
    collectionIds: uniq(r.property_collections),
    assetIds: uniq(r.property_assets),

    raw: r,
  };
}

function normalizeThumbnail(a) {
  return {
    id: a.id ?? null,
    name: a.name ?? null,
    label: a.property_label ?? null,
    type: a.property_type ?? null,
    filename: a.property_filename ?? null,
    relativePath: a.property_relative_path ?? null,

    projectIds: uniq(a.property_projects),
    collectionIds: uniq(a.property_collections),

    // resources attached later (if any resource points at this asset id)
    resources: [],

    raw: a,
  };
}

function normalizeAsset(a, assetById) {
  const thumbId = getFirstRelationId(a.property_thumbnail);
  const thumb =
    thumbId && assetById[thumbId] ? normalizeThumbnail(assetById[thumbId]) : null;

  return {
    id: a.id ?? null,
    name: a.name ?? null,
    label: a.property_label ?? null,
    type: a.property_type ?? null,
    filename: a.property_filename ?? null,
    relativePath: a.property_relative_path ?? null,

    projectIds: uniq(a.property_projects),
    collectionIds: uniq(a.property_collections),

    thumbnail: thumb,

    // resources attached later
    resources: [],

    raw: a,
  };
}

function normalizeCollection(c, assetById) {
  const thumbId = getFirstRelationId(c.property_thumbnail);
  const thumb =
    thumbId && assetById[thumbId] ? normalizeThumbnail(assetById[thumbId]) : null;

  return {
    id: c.id ?? null,
    name: c.name ?? null,
    label: c.property_label ?? null,
    oneLiner: pickFirst(c.property_one_liner) ?? null,
    summary: pickFirst(c.property_summary) ?? null,

    projectIds: uniq(c.property_projects),

    // IDs of assets that are the "collection items"
    collectionItemIds: uniq(c.property_collection_items),

    thumbnail: thumb,

    // attached later
    assets: [],
    resources: [],

    // populated later from collectionItemIds -> normalized asset objects
    items: [],

    raw: c,
  };
}

function normalizeWorkLog(w) {
  const dateVal = parseDateValue(w.property_date);

  return {
    id: w.id ?? null,
    name: w.name ?? null,
    url: w.url ?? null,

    // Common fields from your sample
    entry: w.property_entry ?? w.name ?? null,
    date: dateVal,
    dateRaw: w.property_date ?? null,

    sessionStart: parseDateValue(w.property_session_start),
    sessionEnd: parseDateValue(w.property_session_end),

    public: !!w.property_public,
    projectIds: uniq(w.property_project),

    whatHappened: w.property_what_happened ?? null,
    problems: (typeof w.property_problems === "string" && w.property_problems.trim() === "") ? null : (w.property_problems ?? null),
    nextStep: (typeof w.property_next_step === "string" && w.property_next_step.trim() === "") ? null : (w.property_next_step ?? null),

    sessionType: safeArray(w.property_session_type),
    milestoneIds: uniq(w.property_milestone),
    relatedTaskIds: uniq(w.property_related_tasks),
    sessionIds: uniq(w.property_sessions),

    assetsUrl: w.property_assets_url ?? null,
    assetsFilesMedia: safeArray(w.property_assets_files_media),
    automationLogs: safeArray(w.property_automation_logs),

    allowAutomation: !!w.property_allow_automation,
    feelGoodAboutWork: w.property_feel_good_about_work ?? null,
    accomplishedWhatYouWanted: w.property_accomplished_what_you_wanted ?? null,

    raw: w,
  };
}

function normalizeProject(p, assetById, projectSingleAssetRelationKeys) {
  // If you truly have a separate Project page id field, keep it.
  // Otherwise, p.id is already the Notion page id for the showcase record.
  const projectPageId = pickFirst(p.property_title) ?? p.projectPageId ?? p.id ?? null;

  const singleAssetRelationIds = {};
  const singleAssetMedia = {};
  for (const propertyKey of projectSingleAssetRelationKeys ?? ["property_thumbnail"]) {
    const outputKey = stripPropertyPrefix(propertyKey);
    const resolved = resolveSingleAssetRelation(p, propertyKey, assetById);
    singleAssetRelationIds[outputKey] = resolved.relationId;
    singleAssetMedia[outputKey] = resolved.asset;
  }

  const thumb = singleAssetMedia.thumbnail ?? null;
  const startedAndUpdatedRange = parseStartedLastUpdateRange(
    p.property_started_at_last_update_at
  );
  const startedAt = parseDateValue(p.property_started_at) ?? startedAndUpdatedRange.startedAt ?? null;
  const lastUpdateAt = parseDateValue(p.property_last_update_at) ?? startedAndUpdatedRange.lastUpdateAt ?? null;
  const startedAtLastUpdateAt =
    startedAt || lastUpdateAt
      ? {
          start: startedAt,
          end: lastUpdateAt,
          time_zone: null,
        }
      : null;

  const project = {
    id: p.id ?? null,
    projectPageId,

    title: p.property_name ?? p.name ?? null,
    name: p.property_name ?? p.name ?? null,
    subtitle: pickFirst(p.property_subtitle) ?? null,
    oneLiner: pickFirst(p.property_one_liner) ?? null,
    summary: pickFirst(p.property_summary) ?? null,
    domain: pickFirst(p.property_domain) ?? null,
    featured: !!pickFirst(p.property_featured),
    featuredOrder: p.property_featured_order ?? null,
    tags: safeArray(p.property_tags),
    category: safeArray(p.property_category),
    status: pickFirst(p.property_status) ?? null,
    phase: pickFirst(p.property_phase) ?? null,
    startedAt,
    lastUpdateAt,
    startDate: startedAt,
    lastUpdateDate: lastUpdateAt,
    startedAtLastUpdateAt,
    projectDateRangeRaw: startedAtLastUpdateAt,

    thumbnail: thumb,
    singleAssetMedia,
    singleAssetRelationIds,

    // attached later
    collections: [],
    assets: [],
    resources: [],
    workLogs: [], // <-- added

    // keep raw relations if present (still useful for explicit attach)
    collectionIds: uniq(p.property_collections),
    assetIds: uniq(p.property_assets),
    resourceIds: uniq(p.property_resources),

    raw: p,
  };

  // Keep easy top-level access for single project media fields (banner, hero, icon, etc.)
  // while preserving all existing output keys.
  for (const [key, asset] of Object.entries(singleAssetMedia)) {
    if (key === "thumbnail") continue;
    if (Object.prototype.hasOwnProperty.call(project, key)) continue;
    project[key] = asset;
  }

  return project;
}

// --- Gather items by origin node
const projectsRaw = $items("Query Showcase (Projects)").map((i) => i.json);
const collectionsRaw = $items("Query Collections (All Public)").map((i) => i.json);
const assetsRaw = $items("Query Assets (All Public)").map((i) => i.json);
const resourcesRaw = $items("Query Resources (All Public)").map((i) => i.json);
const workLogsRaw = $items("Query Work Log (All Public)").map((i) => i.json); // <-- added

// --- Index raw assets first (needed for thumbnails)
const assetById = {};
for (const a of assetsRaw) assetById[a.id] = a;
const projectSingleAssetRelationKeys = detectProjectSingleAssetRelationKeys(
  projectsRaw,
  assetById
);

// --- Normalize
const resources = resourcesRaw.map(normalizeResource);
const workLogs = workLogsRaw.map(normalizeWorkLog); // <-- added

const normalizedAssets = assetsRaw.map((a) => normalizeAsset(a, assetById));
const assetNormById = Object.fromEntries(normalizedAssets.map((a) => [a.id, a]));

const normalizedCollections = collectionsRaw.map((c) => normalizeCollection(c, assetById));
const collectionNormById = Object.fromEntries(normalizedCollections.map((c) => [c.id, c]));

const normalizedProjects = projectsRaw.map((p) =>
  normalizeProject(p, assetById, projectSingleAssetRelationKeys)
);
const projectNormById = Object.fromEntries(
  normalizedProjects.map((p) => [p.projectPageId ?? p.id, p])
);

// --- Attach resources to parents (projects/collections/assets)
for (const r of resources) {
  for (const pid of r.projectIds) {
    const p =
      projectNormById[pid] ||
      normalizedProjects.find((x) => x.id === pid || x.projectPageId === pid);
    if (p) p.resources.push(r);
  }
  for (const cid of r.collectionIds) {
    const c = collectionNormById[cid];
    if (c) c.resources.push(r);
  }
  for (const aid of r.assetIds) {
    const a = assetNormById[aid];
    if (a) a.resources.push(r);
  }
}

// --- Attach assets to collections + projects
// (This is "membership via asset.property_collections" and "asset.property_projects")
for (const a of normalizedAssets) {
  for (const cid of a.collectionIds) {
    const c = collectionNormById[cid];
    if (c) c.assets.push(a);
  }
  for (const pid of a.projectIds) {
    const p =
      projectNormById[pid] ||
      normalizedProjects.find((x) => x.id === pid || x.projectPageId === pid);
    if (p) p.assets.push(a);
  }
}

// --- Attach collection items (assets) to collections via collection.property_collection_items
for (const c of normalizedCollections) {
  const itemIds = uniq(c.collectionItemIds);
  c.items = itemIds.map((id) => assetNormById[id]).filter(Boolean);
}

// --- Attach collections to projects
// Prefer explicit relation lists from project rows (property_collections), but also support collection.property_projects.
for (const p of normalizedProjects) {
  const explicit = uniq(p.collectionIds);
  if (explicit.length) {
    for (const cid of explicit) {
      const c = collectionNormById[cid];
      if (c) p.collections.push(c);
    }
  } else {
    // fallback: infer by collection.projectIds
    for (const c of normalizedCollections) {
      if ((c.projectIds ?? []).includes(p.projectPageId) || (c.projectIds ?? []).includes(p.id)) {
        p.collections.push(c);
      }
    }
  }
}

// --- Attach work logs to projects (via workLog.property_project relation)
for (const wl of workLogs) {
  for (const pid of wl.projectIds) {
    const p =
      projectNormById[pid] ||
      normalizedProjects.find((x) => x.id === pid || x.projectPageId === pid);
    if (p) p.workLogs.push(wl);
  }
}

// --- De-dup arrays + sort work logs
for (const p of normalizedProjects) {
  p.resources = dedupById(p.resources);
  p.assets = dedupById(p.assets);
  p.collections = dedupById(p.collections);
  p.workLogs = dedupById(p.workLogs);
  p.workLogs = sortByDateDesc(p.workLogs, (w) => w.date);
}
for (const c of normalizedCollections) {
  c.resources = dedupById(c.resources);
  c.assets = dedupById(c.assets);
  c.items = dedupById(c.items);
}
for (const a of normalizedAssets) {
  a.resources = dedupById(a.resources);
}

// Note: thumbnails are normalized assets but are not included in normalizedAssets unless they are also in assetsRaw.
// If thumbnail assets are included in assetsRaw, they will also receive resources via the same attachment loop above.
// If thumbnails are NOT in assetsRaw (filtered out), they will remain without resources here.

// --- Config (robust + auto fields)
const configItems = $items("Query Config").map(i => i.json);

// Pick a single config row:
// - If "name" is an ISO-ish date (YYYY-MM-DD), pick the max (latest)
// - Else fall back to the first row
const dateLike = (s) => typeof s === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(s);

let configRow = configItems[0] ?? {};
const datedRows = configItems.filter(r => dateLike(r.name));
if (datedRows.length) {
  configRow = datedRows.sort((a, b) => a.name.localeCompare(b.name)).at(-1);
}

// Value normalization helper
function normalizeConfigValue(v) {
  // Flatten 0/1 length arrays
  if (Array.isArray(v)) {
    if (v.length === 0) return null;
    if (v.length === 1) return normalizeConfigValue(v[0]);
    return v.map(normalizeConfigValue);
  }

  // Convert whitespace-only strings to null
  if (typeof v === 'string') {
    const t = v.trim();
    return t === '' ? null : t;
  }

  return v ?? null;
}

const config = Object.fromEntries(
  Object.entries(configRow)
    .filter(([k]) => k.startsWith("property_"))
    .map(([k, v]) => [k.replace(/^property_/, ""), normalizeConfigValue(v)])
    .filter(([, v]) => v !== null)
);

// Optional: keep a top-level copy of all public work logs (sorted)
const workLogsSorted = sortByDateDesc(dedupById(workLogs), (w) => w.date);

return [
  {
    json: {
      config,
      projects: normalizedProjects,
      workLogs: workLogsSorted, // <-- optional top-level export
    },
  },
];

const payload = $json; // whatever your Assemble node outputs (e.g. { projects: [...] })
const text = JSON.stringify(payload, null, 2);

return [
  {
    json: { filename: 'projects.json' },
    binary: {
      data: {
        data: Buffer.from(text, 'utf8').toString('base64'),
        mimeType: 'application/json',
        fileName: 'projects.json',
      },
    },
  },
];
